export function createConfigProvider(
  factory: ConfigFactory & ConfigFactoryKeyHost,
): FactoryProvider {
  return {
    provide: factory.KEY || getConfigToken(randomUUID()),
    useFactory: factory,
    inject: [],
  };
}

canActivate(context: ExecutionContext): boolean {
  const roles = this.reflector.get<string[]>('roles', context.getHandler());
  if (!roles) {
    return true;
  }
  const request = context.switchToHttp().getRequest();
  const user = request.user;
  const hasRole = () =>
    user.roles.some(role => !!roles.find(item => item === role));

  return user && user.roles && hasRole();
}

@GrpcMethod('Math')
  async divide(request: { dividend: number; divisor: number }): Promise<any> {
    if (request.divisor === 0) {
      throw new RpcException({
        code: 3,
        message: 'dividing by 0 is not possible',
      });
    }
    return {
      result: request.dividend / request.divisor,
    };
  }

