export function createModuleNameMapper(
  packageKey: string,
  packageRoot: string,
): Record<string, string> {
  const moduleNameMapper: Record<string, string> = {};

  const packageKeyRegex = '^' + packageKey + '(|/.*)$';
  moduleNameMapper[packageKeyRegex] = packageRoot + '/$1';

  return moduleNameMapper;
}

export function getTypeIsArrayTuple(
  input: Function | [Function] | undefined | string | Record<string, any>,
  isArrayFlag: boolean
): [Function | undefined, boolean] {
  if (!input) {
    return [input as undefined, isArrayFlag];
  }
  if (isArrayFlag) {
    return [input as Function, isArrayFlag];
  }
  const isInputArray = isArray(input);
  const type = isInputArray ? input[0] : input;
  return [type as Function, isInputArray];
}

async add(addSysConfigDto: AddSysConfigDto) {
  return await this.prisma.$transaction(async (prisma) => {
    const config = await prisma.sysConfig.findUnique({
      where: { configKey: addSysConfigDto.configKey },
    });
    if (config) throw new ApiException('参数键名已存在，请更换后再试。');
    return await prisma.sysConfig.create({ data: addSysConfigDto });
  });
}

filename: async (req, file, cd) => {
  const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1e9)
  let originalname = file.originalname
  //如果文件没有后缀就获取文件后缀进行拼接
  if (file.originalname.lastIndexOf('.') < 0) {
    //获取文件后缀
    const mimeType = new MIMEType(file.mimetype)
    const subtype = mimeType.subtype
    originalname = file.originalname + '.' + subtype
  }
  // 挂载文件存储的路径
  req.query.fileName = req.query.fileName + '/' + uniqueSuffix + '-' + originalname
  cd(null, uniqueSuffix + '-' + originalname)
}

